#include "cumsum_reverse_custom_tiling.h"
#include "register/op_def_registry.h"
#include "tiling/tiling_api.h"

namespace optiling {

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    CumsumReverseCustomTilingData tiling;

    // Use storage shape (2-D) to meet 32B alignment on last axis.
    const gert::StorageShape *storage = context->GetInputShape(0);
    const auto &shape2d = storage->GetStorageShape();

    uint32_t outter = shape2d.GetDim(0);
    uint32_t inner  = shape2d.GetDim(1);

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    int32_t dim = 1;
    if (attrs != nullptr && attrs->GetAttrNum() >= 1) {
        const int32_t *pdim = attrs->GetAttrPointer<int32_t>(0);
        if (pdim != nullptr) dim = *pdim;
    }

    // Parallelize by rows.
    uint32_t blockDim = outter;
    if (blockDim == 0) blockDim = 1;
    if (blockDim > 32u) blockDim = 32u;
    context->SetBlockDim(blockDim);

    tiling.set_outter(outter);
    tiling.set_inner(inner);
    tiling.set_dim(dim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {
